const { issues_list, session_id } = $('📥 Input').first().json;
if (!Array.isArray(issues_list)) throw new Error('issues_list muss ein Array sein');
const grouped = {};
for (const issue of issues_list) {
  const key = issue.severity || 'unknown';
  if (!grouped[key]) grouped[key] = [];
  grouped[key].push(issue);
}
const counts = { critical: (grouped.critical||[]).length, warning: (grouped.warning||[]).length, info: (grouped.info||[]).length };
const requires_action = counts.critical > 0 || counts.warning > 2;
return { exit_code: 'success', session_id: session_id || require('crypto').randomUUID(),
  data: { total: issues_list.length, counts, requires_action, grouped, top_issues: issues_list.filter(i=>i.severity==='critical').slice(0,5) },
  timestamp: new Date().toISOString() };
